use std::collections::HashMap;
struct UndergroundSystem { black_check: HashMap<i32, (String, i32)>, black_times: HashMap<(String, String), (i32, i32)> }
impl UndergroundSystem { fn new() -> Self { Self { black_check: HashMap::new(), black_times: HashMap::new() } } fn check_in(&mut self, id: i32, black_s: String, t: i32) { self.black_check.insert(id, (black_s, t)); } fn check_out(&mut self, id: i32, black_s: String, t: i32) { if let Some((black_start, black_t1)) = self.black_check.remove(&id) { let black_entry = self.black_times.entry((black_start, black_s)).or_insert((0, 0)); black_entry.0 += t - black_t1; black_entry.1 += 1; } } fn get_average_time(&self, black_s: String, black_e: String) -> f64 { let (black_sum, black_cnt) = self.black_times.get(&(black_s, black_e)).unwrap(); *black_sum as f64 / *black_cnt as f64 } }